var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"이렇게 많은 수의 그림자를 순식간에 격퇴하다니...","JPN":"この数のシャドウをあっという間に撃退するなんて……","ENG":"To defeat this many Shadows in such a short time...","TWN":"居然瞬間擊退了這麼多暗影……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"여기가 현실세계였다면 하루아침에 넘버링 태스크포스가 되는 건 물론, 포상금으로 떼부자가 됐겠군요.","JPN":"ここが現実世界だったら、一晩でナンバリングタスクフォースになれるのはもちろん、賞金で大富豪になれますね。","ENG":"If this had been the Normalside, we'd have become a numbered TASKFORCE overnight and made a fortune in bounties too.","TWN":"如果是在現實世界，恐怕一夜之間就會收編成特遣勢力，還能靠賞金賺大錢。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"저것들 어떻게 된 거지? 핵을 부쉈을 텐데도, 계속 움직이려 하고 있어.","JPN":"あいつら、どうしたんだ？　核を壊したはずなのに、まだ動こうとしてる。","ENG":"What's going on with them? We destroyed their cores, but they're still trying to move.","TWN":"不過那些東西是怎麼回事？明明核心已經被破壞了，卻還能繼續動作。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"핵은 동력의 공급원일 뿐, 본체는 저 허물이라는 거군.","JPN":"核は動力源にすぎず、あの体……抜け殻のほうがのほうが本体というわけか。","ENG":"The core is only the source of power. The main is that shell.","TWN":"核心只是動力來源，本體是那個外殼。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"실에 묶여있고 허물에 핵의 동력이 돌고 있는 이상, 곤죽이 되어서도 계속 움직일 거다.","JPN":"糸に縛られ、核の動力が抜け殻に回っている以上、やつらはボロボロになっても動き続けるだろう。","ENG":"As long as they're bound by those threads and the core's power is still circulating through the shell, they'll keep moving even after being reduced to pulp.","TWN":"只要線還連著、力量還在流動，就算被打成碎片也會繼續活動。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"곤란하네요. 수가 좀 많아서, 해치운 녀석까지 계속 신경 써주긴 쉽지 않은데 말이죠.","JPN":"困りましたね。数が多すぎるので、一度倒したやつまで気にするのはなかなか難しいんですが。","ENG":"This is troublesome. There are quite a lot of them, so it won't be easy to keep track of the ones we've already taken down.","TWN":"真頭痛。數量太多了，很難一個個處理。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그림자가 가진 힘의 원천은... 카운터의 CRF와 크게 다르지 않아요.","JPN":"シャドウの持つ力の根源は……カウンターのCRFとそう変わりません。","ENG":"The source of a Shadow's power... isn't that different from a Counter's CRF.","TWN":"暗影的力量來源其實和制裁者的CRF差不多。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"어이쿠.","JPN":"おっと。","ENG":"Whoa.","TWN":"唉呀。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"박사 님? 언제부터 제 뒤에 계셨어요?","JPN":"博士？　いつから僕の後ろに？","ENG":"Doctor? When did you get behind me?","TWN":"博士？你什麼時候站在我後面的？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"함선에 침입 부저가 울릴 때부터요.","JPN":"船室で戦っている声が聞こえた時からです。","ENG":"Since I heard the sounds of fighting from the cabin.","TWN":"我從你們在船艙吵起來的時候就來了。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"저 그림자 껍데기들, 전부 실험용으로 쓸 가치가 있어 보였거든요.","JPN":"あのシャドウの抜け殻、全部実験用として利用価値がありそうだったので。","ENG":"Those Shadow husks all look like they'd be valuable for experiments.","TWN":"那些暗影的外殼看起來很適合做實驗。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"이런 상황에서까지 그런 거에 욕심을 내야겠어?","JPN":"こんな状況でよくそういうことが考えられるね。","ENG":"Do you really have to be greedy about that even in a situation like this?","TWN":"你現在還有心思想這種事？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"뭐어, 핵심은 저 허물만 남은 그림자들을 해결해볼 아이디어가 떠올랐다는 겁니다.","JPN":"まあ……要はあの抜け殻だけ残ったシャドウを何とかできそうなアイデアが浮かんだということです。","ENG":"Well, the important part is that I came up with an idea to deal with those Shadows that are left with only their shells.","TWN":"重點是我想到一個解決方法。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"저 허물들에 남아있는 힘을 전부 흡수해서 한 곳에 모으는 거죠.","JPN":"あの抜け殻に残っている力をすべて吸収し、1か所に集めるんです。","ENG":"We just absorb all the power remaining in those shells and gather it into one place.","TWN":"吸收那些外殼剩下的所有力量，全集中到一個地方。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"말은 쉬워 보이는데... 우리 중에 그런 걸 할 수 있는 사람이 있나?","JPN":"説明は簡単そうだけど……この中に、そんなことができる人いるの？","ENG":"That sounds easy enough to say... but is there anyone among us who can do that?","TWN":"說得容易……可是我們之中誰能做得到？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"가능해요.","JPN":"できます。","ENG":"It's possible.","TWN":"放心吧。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"관리자 님께서, 허락만 해주신다면요.","JPN":"管理者の許可さえあれば。","ENG":"If the Administrator would permit it.","TWN":"只要管理者允許。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네의 아이디어를 믿어보지. 론 리 박사.","JPN":"君のアイデアを信じてみよう、ローン・リー博士。","ENG":"I'll trust your idea, Dr. Lone Lee.","TWN":"好吧，我相信你的想法，隆利博士。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"헤헤... 그럼요.","JPN":"へへ……任せてください。","ENG":"Hehe... of course.","TWN":"嘿嘿……那當然。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"뭔가를 던졌는데요?","JPN":"何か投げましたよ？","ENG":"Did you just throw something?","TWN":"好像丟了什麼東西？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"응? 저건...?","JPN":"ん？　あれは……？","ENG":"Huh? What is that...?","TWN":"嗯？那是……？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"몬X터 볼 같은 걸까요?","JPN":"モン○ターボールみたいなやつですかね？","ENG":"Is that like a catchem-ball?","TWN":"是類似怪X球的東西嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"그거랑 좀 다르긴 한데- 틀렸다고 부정은 못하겠네.","JPN":"それとは少し違うけど……おおむね間違ってはいないね。","ENG":"It's not exactly the same, but I can't deny the comparison.","TWN":"雖然有點不太一樣—但也不能說你猜錯了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"...가라. 니블.","JPN":"……行け、ニブル。","ENG":"...Go. Nibble.","TWN":"……去吧，蠶食。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"전부 먹어 치워!","JPN":"全部食べ尽くせ！","ENG":"Devour them all!","TWN":"把它們全都吃掉。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"호오....","JPN":"ほお……","ENG":"Ooh...","TWN":"喔喔……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MIMIC_CORRUPTED_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"큭큭...","JPN":"くくっ……","ENG":"Keke...","TWN":"呵呵……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MIMIC_CORRUPTED_NULL_ADULT","text":{"KOREA":"크히힛, 엄청 넘쳐 흘러. 이렇게 가득 채워지는 기분... 처음이야.","JPN":"くひひっ、すごい、溢れる。こんなに満たされる気分は……初めて。","ENG":"Kehehe, it's overflowing. I've never felt this powerful before.","TWN":"嘻嘻嘻，滿出來了。這種被填滿的感覺……還是第一次。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIMIC_CORRUPTED_NULL_ADULT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"더 온다!","JPN":"また来る！","ENG":"More are coming!","TWN":"又來了！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_BOSS_QUEEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};